import json
from typing import Any, Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): Input metadata as a pre-parsed dict or a raw JSON string.
            If a string is provided, json.loads() is called explicitly before processing.
        max_depth (int): Maximum nesting depth allowed. Defaults to 20. The root dict is
            processed at depth=0 (meaning depth=0 processes the root dict and its direct
            children, depth=1 means the second level of nesting, and so on). A ValueError
            is raised when depth reaches max_depth (i.e., depth >= max_depth), so exactly
            max_depth levels of nesting are permitted.

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation
            (e.g., 'network.interfaces.0.mac'). If the root value is not a dict after
            parsing, returns {"" : <scalar_value>}.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string input cannot be parsed by json.loads().
        ValueError: If nesting depth reaches max_depth during recursion.

    Examples:
        >>> result = flatten_ec2_metadata(
        ...     {"instance": {"id": "i-1234", "tags": ["web", "prod"]}},
        ...     max_depth=20
        ... )
        >>> result == {"instance.id": "i-1234", "instance.tags.0": "web", "instance.tags.1": "prod"}
        True

        >>> import pytest
        >>> deep = {"a": {"b": {"c": {"d": {"e": {"f": {"g": {"h": {"i": {"j": {"k": {"l": {"m": {"n": {"o": {"p": {"q": {"r": {"s": {"t": {"u": "v"}}}}}}}}}}}}}}}}}}}}}
        >>> try:
        ...     flatten_ec2_metadata(deep, max_depth=20)
        ... except ValueError as e:
        ...     print("ValueError raised")
        ValueError raised
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError("Input must be a dict or a JSON string, not None or other types.")

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    result = {}

    def _flatten(obj: Any, prefix: str, depth: int) -> None:
        if depth >= max_depth:
            raise ValueError(
                f"Maximum nesting depth of {max_depth} exceeded at key '{prefix}'."
            )
        if isinstance(obj, dict):
            for key, value in obj.items():
                new_key = prefix + "." + key if prefix else key
                if isinstance(value, dict):
                    _flatten(value, new_key, depth + 1)
                elif isinstance(value, list):
                    for i, item in enumerate(value):
                        item_key = new_key + "." + str(i)
                        if isinstance(item, dict):
                            if depth + 1 >= max_depth:
                                raise ValueError(
                                    f"Maximum nesting depth of {max_depth} exceeded at key '{item_key}'."
                                )
                            _flatten(item, item_key, depth + 1)
                        else:
                            if depth + 1 >= max_depth:
                                raise ValueError(
                                    f"Maximum nesting depth of {max_depth} exceeded at key '{item_key}'."
                                )
                            result[item_key] = item
                else:
                    result[new_key] = value

    _flatten(data, "", 0)
    return result

from typing import List, Dict, Any


def _extract_value(typed_dict: Dict[str, Any]) -> Any:
    """
    Extract value from a DynamoDB typed dict.

    Raises:
        ValueError: If the typed dict is empty or contains an unsupported type key.
    """
    if not typed_dict:
        raise ValueError("Empty type dict")
    type_key = next(iter(typed_dict))
    value = typed_dict[type_key]
    if type_key == "S":
        return value
    elif type_key == "N":
        return value
    elif type_key == "BOOL":
        return value
    else:
        raise ValueError(f"Unsupported DynamoDB type key: {type_key}")


def filter_dynamodb_items(
    items: List[Dict],
    attribute_name: str,
    condition_value: Any,
) -> List[Dict]:
    """
    Filter DynamoDB items based on a simple attribute condition.

    Parameters:
        items: List of item dicts in DynamoDB boto3 typed format,
               e.g. [{'attr': {'S': 'value'}}, {'attr': {'N': '123'}}].
        attribute_name: The attribute name to filter on.
        condition_value: The value to compare against. For N type attributes,
                         condition_value may be either a number or a numeric string;
                         both the stored value and condition_value will be coerced
                         to float for comparison using float(stored) == float(condition_value).

    Returns:
        A list of items where the attribute matches condition_value.

    Raises:
        ValueError: If items is None.
        ValueError: If any element in items is not a dict.
        ValueError: If attribute_name is not a string.
        ValueError: If attribute_name is an empty string.
        ValueError: If a typed value dict is empty or has an unsupported type key.
    """
    if items is None:
        raise ValueError("items must not be None")
    for item in items:
        if not isinstance(item, dict):
            raise ValueError(f"All elements in items must be dicts, got: {type(item)}")
    if not isinstance(attribute_name, str):
        raise ValueError(f"attribute_name must be a string, got: {type(attribute_name)}")
    if attribute_name == "":
        raise ValueError("attribute_name must not be an empty string")

    result = []
    for item in items:
        if attribute_name not in item:
            continue
        typed_dict = item[attribute_name]
        type_key = next(iter(typed_dict)) if typed_dict else None
        stored = _extract_value(typed_dict)
        if type_key == "N":
            if float(stored) == float(condition_value):
                result.append(item)
        else:
            if stored == condition_value:
                result.append(item)
    return result
